frappe.ui.form.on("Series Manager List", {
   isdefault: function(frm, cdt, cdn) 
    { 
        var onchangedata = locals[cdt][cdn];
        for(var i= 0;i<=frm.doc.series_list.length-1;i++)
        {
            if(frm.doc.series_list[i].name != onchangedata.name)
            {
                frm.doc.series_list[i].isdefault = 0;
            }
            if(frm.doc.series_list[i].ischecked === 0)
            {
                frm.doc.series_list[i].isdefault = 0;
            }
        }
        frm.refresh();
    }
});

frappe.ui.form.on('User HTML Block', {
    generate_html: function (frm) {

        const design_rows = frm.doc.design || [];
        const report_rows = frm.doc.reports || [];

        let mastersHTML = `
<div class="container">
  <h2>Masters</h2>
  <div class="grid">
`;

        design_rows.forEach(row => {
            const doctype = row.select_doctype || "";
            const label = row.label || doctype;
            const desc = row.description || `Manage ${label}`;
            const icon = row.file_name || "";
            const color = row.color || "bg-purple";

            mastersHTML += `
    <div class="dashboard-card" data-doctype="${doctype}">
      <div class="card ${color}">
        <div class="header">
          <div class="icon">
            <img src="${icon}">
          </div>
          <h3>${label}</h3>
        </div>

        <div class="mb-2">
          <span style="position:absolute;right:10px;top:10px;"></span>
        </div>

        <div class="mt-auto">
          <p class="small">${desc}</p>
        </div>
      </div>
    </div>
`;
        });

        mastersHTML += `
  </div>
</div>
`;

        let reportsHTML = `
<section>
  <h2 class="section-title">Reports</h2>
  <div class="reports-container">
    <div>
      <div class="row">
`;

        report_rows.forEach(row => {
            const report = row.report || "";
            const label = row.label || report;

            reportsHTML += `
        <div class="col-12 col-md-4">
          <div class="report-card">
            <div class="dashboard-card" data-report="${report}">
              <h4>${label}</h4>
            </div>
          </div>
        </div>
`;
        });

        reportsHTML += `
      </div>
    </div>
  </div>
</section>
`;

        frm.set_value("html", mastersHTML + reportsHTML);
    }
});
frappe.ui.form.on('User HTML Block', {
    create_custom_block: function (frm) {

        const user = frm.doc.user || frappe.session.user;
        const module = frm.doc.module;
        const html = frm.doc.html || '';
        const js = frm.doc.js || '';
        const css = frm.doc.css || '';

        if (!module) {
            frappe.msgprint("⚠️ Please select Module");
            return;
        }

        const custom_name = `${user}-${module}`;

        frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Custom HTML Block",
                name: custom_name
            },
            callback: function (r) {

                if (r.message) {
                    frappe.msgprint({
                        title: "Already Exists",
                        message: `Custom HTML Block <b>${custom_name}</b> already exists.`,
                        indicator: "orange"
                    });
                    frappe.set_route("Form", "Custom HTML Block", custom_name);
                    return;
                }
            },
            error: function () {

                frappe.call({
                    method: "frappe.client.insert",
                    args: {
                        doc: {
                            doctype: "Custom HTML Block",
                            html: html,
                            script: js,
                            style: css,
                            __newname: custom_name
                        }
                    },
                    callback: function (res) {
                        if (res.message) {
                            frappe.msgprint({
                                message: `✅ Custom HTML Block <b>${res.message.name}</b> created`,
                                indicator: "green"
                            });

                            frappe.set_route(
                                "Form",
                                "Custom HTML Block",
                                res.message.name
                            );
                        }
                    }
                });
            }
        });
    }
});
